transform_js:
const titles = []; const measures = []; const targets = []; const ranges = [];
// 順序を反転（下から上へ描画されるため）
[...rawData.rows].reverse().forEach(r => {
  titles.push(r.title);
  measures.push(r.measure);
  targets.push(r.target);
  ranges.push(r.maxRange);
});
transformedData = { titles, measures, targets, ranges };

echarts_js:
option = {
  title: {
    text: 'KPI Dashboards (Bullet Chart)',
    left: 'center'
  },
  grid: { left: '15%', right: '5%', top: '15%', bottom: '10%' },
  xAxis: {
    type: 'value',
    splitLine: { show: false }
  },
  yAxis: {
    type: 'category',
    data: transformedData.titles,
    axisTick: { show: false },
    axisLine: { show: false }
  },
  series: [
    {
      name: 'Background Range',
      type: 'bar',
      barWidth: '60%',
      itemStyle: { color: '#eee' },
      data: transformedData.ranges,
      animation: false
    },
    {
      name: 'Measure',
      type: 'bar',
      barWidth: '25%',
      barGap: '-70%', // 重ねるための設定
      z: 3,
      itemStyle: { color: '#333' },
      data: transformedData.measures
    },
    {
      name: 'Target',
      type: 'scatter',
      symbol: 'rect',
      symbolSize: [5, 40], // 縦長のマーカーとして目標値を描画
      z: 4,
      itemStyle: { color: '#e54035' },
      data: transformedData.targets
    }
  ]
};
